content.PrologProcedure:
#****Begin: Generated Statements***
#****End: Generated Statements****
# =============================================
# PROLOG 
# =============================================
sCube = 'CST Activity Config';
sDim_Period      = 'GBL Period';
sDim_Version     = 'GBL Version';
sDim_CostPool    = 'CST Cost Pool';
sDim_ServiceLine = 'CST Driver';
sDim_CostCentre  = 'CST Activity';
sDim_Measure     = 'CST Activity Config Measure';
# CLEAR CUBEVIEW
sView = 'TI_Clear_Amount';
sSubset = sView;
IF(ViewExists(sCube, sView) = 1);
    ViewDestroy(sCube, sView);
ENDIF;
IF(SubsetExists(sDim_Measure, sSubset) = 1);
    SubsetDestroy(sDim_Measure, sSubset);
ENDIF;
# Create subset with only "Amount"
SubsetCreate(sDim_Measure, sSubset);
SubsetElementInsert(sDim_Measure, sSubset, 'Activity to Service Line Basis', 1);
SubsetElementInsert(sDim_Measure, sSubset, 'Driver Value', 1);
SubsetElementInsert(sDim_Measure, sSubset, 'Driver Percentage Share', 1);
# Create view with subset
ViewCreate(sCube, sView, 1);
ViewSubsetAssign(sCube, sView, sDim_Measure, sView);
#Zero
ViewZeroOut(sCube, sView);
#Cleanup
ViewDestroy(sCube, sView);
LogOutput('INFO', 'Cleared only "Amount" measure from cube');

